#!/usr/bin/env python3

import os
import sys
import json
import hashlib
import subprocess
import argparse
from pathlib import Path
from typing import List, Dict, Optional, Set
from datetime import datetime
import re


class DependencyLockManager:
    """Manages Python dependency lock files with hashes for reproducible builds"""
    
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_in = self.project_root / "requirements.in"
        self.requirements_txt = self.project_root / "requirements.txt"
        self.requirements_dev_in = self.project_root / "requirements-dev.in"
        self.requirements_dev_txt = self.project_root / "requirements-dev.txt"
        self.lock_metadata = self.project_root / ".lock-metadata.json"
        
    def check_pip_tools_installed(self) -> bool:
        """Check if pip-tools is installed"""
        try:
            subprocess.run(
                ["pip-compile", "--version"],
                capture_output=True,
                check=True
            )
            return True
        except (subprocess.CalledProcessError, FileNotFoundError):
            return False
    
    def install_pip_tools(self):
        """Install pip-tools for lock file generation"""
        print("Installing pip-tools...")
        subprocess.run(
            [sys.executable, "-m", "pip", "install", "pip-tools"],
            check=True
        )
        print("pip-tools installed successfully")
    
    def create_requirements_in(self, dependencies: List[str]):
        """Create requirements.in file with base dependencies"""
        with open(self.requirements_in, 'w') as f:
            f.write("# Base project dependencies\n")
            f.write(f"# Generated on {datetime.now().isoformat()}\n\n")
            for dep in dependencies:
                f.write(f"{dep}\n")
        print(f"Created {self.requirements_in}")
    
    def create_dev_requirements_in(self, dev_dependencies: List[str]):
        """Create requirements-dev.in file with development dependencies"""
        with open(self.requirements_dev_in, 'w') as f:
            f.write("# Development dependencies\n")
            f.write(f"# Generated on {datetime.now().isoformat()}\n\n")
            f.write("-c requirements.txt\n\n")
            for dep in dev_dependencies:
                f.write(f"{dep}\n")
        print(f"Created {self.requirements_dev_in}")
    
    def compile_requirements(self, upgrade: bool = False, upgrade_package: Optional[str] = None):
        """Compile requirements.in to requirements.txt with hashes"""
        if not self.requirements_in.exists():
            raise FileNotFoundError(f"{self.requirements_in} not found")
        
        cmd = [
            "pip-compile",
            "--generate-hashes",
            "--output-file", str(self.requirements_txt),
            str(self.requirements_in)
        ]
        
        if upgrade:
            cmd.append("--upgrade")
        elif upgrade_package:
            cmd.extend(["--upgrade-package", upgrade_package])
        
        print(f"Compiling {self.requirements_in}...")
        subprocess.run(cmd, check=True)
        print(f"Generated {self.requirements_txt}")
        
        self._save_metadata("production")
    
    def compile_dev_requirements(self, upgrade: bool = False, upgrade_package: Optional[str] = None):
        """Compile requirements-dev.in to requirements-dev.txt with hashes"""
        if not self.requirements_dev_in.exists():
            raise FileNotFoundError(f"{self.requirements_dev_in} not found")
        
        if not self.requirements_txt.exists():
            print("Compiling production requirements first...")
            self.compile_requirements()
        
        cmd = [
            "pip-compile",
            "--generate-hashes",
            "--output-file", str(self.requirements_dev_txt),
            str(self.requirements_dev_in)
        ]
        
        if upgrade:
            cmd.append("--upgrade")
        elif upgrade_package:
            cmd.extend(["--upgrade-package", upgrade_package])
        
        print(f"Compiling {self.requirements_dev_in}...")
        subprocess.run(cmd, check=True)
        print(f"Generated {self.requirements_dev_txt}")
        
        self._save_metadata("development")
    
    def sync_dependencies(self, dev: bool = False):
        """Sync installed packages with lock file using pip-sync"""
        lock_file = self.requirements_dev_txt if dev else self.requirements_txt
        
        if not lock_file.exists():
            raise FileNotFoundError(f"{lock_file} not found. Run compile first.")
        
        cmd = ["pip-sync"]
        if dev:
            cmd.extend([str(self.requirements_txt), str(self.requirements_dev_txt)])
        else:
            cmd.append(str(self.requirements_txt))
        
        print(f"Syncing dependencies from {lock_file}...")
        subprocess.run(cmd, check=True)
        print("Dependencies synced successfully")
    
    def verify_hashes(self, lock_file: Optional[Path] = None) -> bool:
        """Verify that lock file contains hashes for all packages"""
        if lock_file is None:
            lock_file = self.requirements_txt
        
        if not lock_file.exists():
            print(f"Lock file {lock_file} not found")
            return False
        
        with open(lock_file, 'r') as f:
            content = f.read()
        
        packages = re.findall(r'^([a-zA-Z0-9\-_]+)==', content, re.MULTILINE)
        hashes = re.findall(r'--hash=', content)
        
        if not packages:
            print("No packages found in lock file")
            return False
        
        if not hashes:
            print("WARNING: No hashes found in lock file!")
            return False
        
        print(f"Lock file contains {len(packages)} packages with {len(hashes)} hashes")
        return True
    
    def extract_dependencies(self, lock_file: Optional[Path] = None) -> Dict[str, str]:
        """Extract package names and versions from lock file"""
        if lock_file is None:
            lock_file = self.requirements_txt
        
        dependencies = {}
        
        with open(lock_file, 'r') as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith('#') and not line.startswith('--'):
                    match = re.match(r'^([a-zA-Z0-9\-_]+)==([0-9\.]+)', line)
                    if match:
                        dependencies[match.group(1)] = match.group(2)
        
        return dependencies
    
    def compare_lock_files(self, file1: Path, file2: Path) -> Dict[str, any]:
        """Compare two lock files and show differences"""
        deps1 = self.extract_dependencies(file1)
        deps2 = self.extract_dependencies(file2)
        
        added = {k: v for k, v in deps2.items() if k not in deps1}
        removed = {k: v for k, v in deps1.items() if k not in deps2}
        updated = {
            k: {'old': deps1[k], 'new': deps2[k]}
            for k in deps1.keys() & deps2.keys()
            if deps1[k] != deps2[k]
        }
        
        return {
            'added': added,
            'removed': removed,
            'updated': updated
        }
    
    def _save_metadata(self, env_type: str):
        """Save metadata about lock file generation"""
        metadata = {}
        if self.lock_metadata.exists():
            with open(self.lock_metadata, 'r') as f:
                metadata = json.load(f)
        
        metadata[env_type] = {
            'timestamp': datetime.now().isoformat(),
            'python_version': sys.version,
            'pip_tools_version': self._get_pip_tools_version()
        }
        
        with open(self.lock_metadata, 'w') as f:
            json.dump(metadata, f, indent=2)
    
    def _get_pip_tools_version(self) -> str:
        """Get pip-tools version"""
        try:
            result = subprocess.run(
                ["pip-compile", "--version"],
                capture_output=True,
                text=True,
                check=True
            )
            return result.stdout.strip()
        except:
            return "unknown"
    
    def check_outdated(self) -> List[Dict[str, str]]:
        """Check for outdated packages"""
        result = subprocess.run(
            [sys.executable, "-m", "pip", "list", "--outdated", "--format=json"],
            capture_output=True,
            text=True,
            check=True
        )
        
        return json.loads(result.stdout)
    
    def generate_dependency_tree(self) -> str:
        """Generate dependency tree"""
        try:
            result = subprocess.run(
                ["pipdeptree", "--json"],
                capture_output=True,
                text=True,
                check=True
            )
            return result.stdout
        except FileNotFoundError:
            print("pipdeptree not installed. Install with: pip install pipdeptree")
            return "[]"


class PoetryLockManager:
    """Manages Poetry lock files"""
    
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.pyproject_toml = self.project_root / "pyproject.toml"
        self.poetry_lock = self.project_root / "poetry.lock"
    
    def check_poetry_installed(self) -> bool:
        """Check if Poetry is installed"""
        try:
            subprocess.run(
                ["poetry", "--version"],
                capture_output=True,
                check=True
            )
            return True
        except (subprocess.CalledProcessError, FileNotFoundError):
            return False
    
    def init_project(self, name: str, description: str = ""):
        """Initialize a new Poetry project"""
        cmd = ["poetry", "init", "--no-interaction"]
        if name:
            cmd.extend(["--name", name])
        if description:
            cmd.extend(["--description", description])
        
        subprocess.run(cmd, check=True)
        print(f"Initialized Poetry project: {name}")
    
    def add_dependency(self, package: str, dev: bool = False, version: Optional[str] = None):
        """Add a dependency to pyproject.toml"""
        cmd = ["poetry", "add"]
        if dev:
            cmd.append("--group=dev")
        
        if version:
            cmd.append(f"{package}@{version}")
        else:
            cmd.append(package)
        
        subprocess.run(cmd, check=True)
        print(f"Added {package} to dependencies")
    
    def remove_dependency(self, package: str, dev: bool = False):
        """Remove a dependency from pyproject.toml"""
        cmd = ["poetry", "remove"]
        if dev:
            cmd.append("--group=dev")
        cmd.append(package)
        
        subprocess.run(cmd, check=True)
        print(f"Removed {package} from dependencies")
    
    def lock_dependencies(self, no_update: bool = False):
        """Generate or update poetry.lock file"""
        cmd = ["poetry", "lock"]
        if no_update:
            cmd.append("--no-update")
        
        print("Locking dependencies...")
        subprocess.run(cmd, check=True)
        print(f"Generated/updated {self.poetry_lock}")
    
    def install_dependencies(self, no_dev: bool = False, sync: bool = True):
        """Install dependencies from poetry.lock"""
        cmd = ["poetry", "install"]
        if no_dev:
            cmd.append("--no-dev")
        if sync:
            cmd.append("--sync")
        
        print("Installing dependencies...")
        subprocess.run(cmd, check=True)
        print("Dependencies installed successfully")
    
    def update_dependencies(self, package: Optional[str] = None):
        """Update dependencies"""
        cmd = ["poetry", "update"]
        if package:
            cmd.append(package)
        
        print("Updating dependencies...")
        subprocess.run(cmd, check=True)
        print("Dependencies updated")
    
    def show_dependencies(self, tree: bool = False, outdated: bool = False):
        """Show installed dependencies"""
        cmd = ["poetry", "show"]
        if tree:
            cmd.append("--tree")
        if outdated:
            cmd.append("--outdated")
        
        subprocess.run(cmd)
    
    def export_requirements(self, output_file: str = "requirements.txt", dev: bool = False):
        """Export dependencies to requirements.txt format"""
        cmd = ["poetry", "export", "-f", "requirements.txt", "-o", output_file]
        if dev:
            cmd.append("--with=dev")
        
        subprocess.run(cmd, check=True)
        print(f"Exported dependencies to {output_file}")
    
    def check_lock_file(self) -> bool:
        """Check if poetry.lock is up to date"""
        try:
            subprocess.run(
                ["poetry", "lock", "--check"],
                capture_output=True,
                check=True
            )
            print("poetry.lock is up to date")
            return True
        except subprocess.CalledProcessError:
            print("poetry.lock is out of date. Run 'poetry lock' to update.")
            return False


